// --- CONFIGURACIÓN ---
const TIMEZONE = 'America/New_York';
const START_HOUR = 8;  // 8 AM
const END_HOUR = 18;   // 6 PM
const WORK_DAYS = [1, 2, 3, 4, 5, 6]; // 1=Lunes ... 6=Sábado


// =============================
// OBTENER Y PREPARAR EVENTOS
// =============================

// Todos los eventos que entran al nodo
const allEvents = $input.all().map(item => item.json);

// ID del evento que se está reagendando (viene del nodo Get an event)
const eventIdToIgnore = $node["Get an event"].json.id;

// Buscar ese evento en la lista
const eventToReschedule = allEvents.find(e => e.id === eventIdToIgnore);

// Determinar si se debe excluir
let eventsInput;

if (eventToReschedule && eventToReschedule.summary !== "Not available") {
  // Es una cita normal → se excluye del cálculo
  eventsInput = allEvents.filter(e => e.id !== eventIdToIgnore);
} else {
  // Es "Not available" → NO se excluye nada
  eventsInput = allEvents;
}


// =============================
// CALCULAR DISPONIBILIDAD
// =============================

// Formateador para fechas en NY
const nyFormatter = new Intl.DateTimeFormat('en-CA', {
  timeZone: TIMEZONE,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
});

// Hoy en NY (YYYY-MM-DD)
const todayNYString = nyFormatter.format(new Date());

// Mañana en NY
const startDate = new Date(`${todayNYString}T00:00:00`);
startDate.setDate(startDate.getDate() + 1);

// Rango 30 días
const endDate = new Date(startDate);
endDate.setDate(startDate.getDate() + 30);

let finalAvailability = [];
let currentLoopDate = new Date(startDate);

while (currentLoopDate <= endDate) {

  const loopDateNY = nyFormatter.format(currentLoopDate);

  // Saltar hoy
  if (loopDateNY === todayNYString) {
    currentLoopDate.setDate(currentLoopDate.getDate() + 1);
    continue;
  }

  const dayOfWeek = new Date(loopDateNY + 'T00:00:00').getDay();

  if (WORK_DAYS.includes(dayOfWeek)) {

    const currentDateString = loopDateNY;

    // Eventos del día actual
    const daysEvents = eventsInput.filter(e => {
      if (!e.start || !e.start.dateTime) return false;
      const evtDate = new Date(e.start.dateTime);
      const evtDateNY = nyFormatter.format(evtDate);
      return evtDateNY === currentDateString;
    });

    const dayStartMins = START_HOUR * 60;
    const dayEndMins = END_HOUR * 60;

    let slots = [{ start: dayStartMins, end: dayEndMins }];

    daysEvents.forEach(evt => {

      const evtStart = new Date(evt.start.dateTime);
      const evtEnd = new Date(evt.end.dateTime);

      const getMins = (date) => {
        const parts = new Intl.DateTimeFormat('en-US', {
          timeZone: TIMEZONE,
          hour: 'numeric',
          minute: 'numeric',
          hour12: false
        }).formatToParts(date);

        let h = parseInt(parts.find(p => p.type === 'hour').value);
        if (h === 24) h = 0;

        const m = parseInt(parts.find(p => p.type === 'minute').value);
        return (h * 60) + m;
      };

      const eStartMins = getMins(evtStart);
      const eEndMins = getMins(evtEnd);

      let newSlots = [];

      slots.forEach(slot => {

        if (eEndMins <= slot.start || eStartMins >= slot.end) {
          newSlots.push(slot);
        } else {

          if (slot.start < eStartMins) {
            newSlots.push({ start: slot.start, end: eStartMins });
          }

          if (slot.end > eEndMins) {
            newSlots.push({ start: eEndMins, end: slot.end });
          }
        }
      });

      slots = newSlots;
    });

    if (slots.length > 0) {

      slots.sort((a, b) => a.start - b.start);

      const minsToTime = (mins) => {
        const h = Math.floor(mins / 60);
        const m = mins % 60;
        const ampm = h >= 12 ? 'PM' : 'AM';
        const h12 = h % 12 || 12;
        return `${h12}:${String(m).padStart(2, '0')} ${ampm}`;
      };

      const disponibilidad = slots.map(s => ({
        start: minsToTime(s.start),
        end: minsToTime(s.end),
        Disponibilidad: `${minsToTime(s.start)} – ${minsToTime(s.end)}`
      }));

      finalAvailability.push({
        date: currentDateString,
        disponibilidad: disponibilidad
      });
    }
  }

  currentLoopDate.setDate(currentLoopDate.getDate() + 1);
}

return finalAvailability;
